  3,
  'Procedimento Operacional',
  'ckeditor5',
  'html',
  $$<section class="md-doc-shell">
  <header class="md-doc-header">
    <h1>Procedimento Operacional</h1>
    <p class="md-doc-type">Tipo: PO</p>
