        <tbody>
          <tr><td>Ex: SLA</td><td>Ex: Acordo de nível de serviço</td></tr>
        </tbody>
      </table>
    </figure>
  </section>
</section>$$,
  '{}'::jsonb
)
ON CONFLICT (template_key, version) DO NOTHING;

-- Update PO profile default to the new browser template
UPDATE metaldocs.document_profile_template_defaults
SET template_key = 'po-default-browser',
    template_version = 1,
    assigned_at = NOW()
WHERE profile_code = 'po';

-- Insert if no default exists yet
INSERT INTO metaldocs.document_profile_template_defaults (profile_code, template_key, template_version)
VALUES ('po', 'po-default-browser', 1)
ON CONFLICT (profile_code) DO NOTHING;
